private fun Project.configureAndroidAbiValidation(
    subdirectoryName: String,
    dependencyTaskNames: List<String>,
    classfiles: FileCollection,
) {
    val dependencyTasks = tasks.matching { it.name in dependencyTaskNames }
    tasks.matching { it.name == "internalDumpKotlinAbi" }.configureEach {
        dependsOn(dependencyTasks)
        configureKotlinAbiDumpInput(subdirectoryName, classfiles)
    }
}

override fun MeasureScope.measure(
    measurable: Measurable,
    constraints: Constraints,
): MeasureResult {
    setConstraints(constraints)

    // Measure and layout the content.
    val placeable = measurable.measure(constraints)
    return layout(placeable.width, placeable.height) {
        placeable.place(0, 0)
    }
}

override fun create(): SubcomposeContentPainterNode {
    return SubcomposeContentPainterNode(
        painter = painter,
        alignment = alignment,
        contentScale = contentScale,
        alpha = alpha,
        colorFilter = colorFilter,
        clipToBounds = clipToBounds,
        contentDescription = contentDescription,
    )
}

override fun MeasureScope.measure(
    measurable: Measurable,
    constraints: Constraints,
): MeasureResult {
    constraintSizeResolver?.setConstraints(constraints)

    val placeable = measurable.measure(modifyConstraints(constraints))
    return layout(placeable.width, placeable.height) {
        placeable.placeRelative(0, 0)
    }
}

override fun IntrinsicMeasureScope.minIntrinsicWidth(
    measurable: IntrinsicMeasurable,
    height: Int,
): Int {
    val constraints = Constraints(maxHeight = height)
    constraintSizeResolver?.setConstraints(constraints)

    return if (painter.intrinsicSize.isSpecified) {
        val modifiedConstraints = modifyConstraints(constraints)
        val layoutWidth = measurable.minIntrinsicWidth(height)
        max(modifiedConstraints.minWidth, layoutWidth)
    } else {
        measurable.minIntrinsicWidth(height)
    }
}

