override fun SemanticsPropertyReceiver.applySemantics() {
    val contentDescription = this@AbstractContentPainterNode.contentDescription
    if (contentDescription != null) {
        this.contentDescription = contentDescription
        this.role = Role.Image
    }
}

override fun newContext(
    old: CoroutineContext,
    new: CoroutineContext,
): ForwardingCoroutineContext {
    val oldDispatcher = old.dispatcher
    val newDispatcher = new.dispatcher
    if (oldDispatcher is DeferredDispatchCoroutineDispatcher && oldDispatcher != newDispatcher) {
        oldDispatcher.unconfined = false
    }

    return DeferredDispatchCoroutineContext(new)
}

override fun create(
    result: SourceFetchResult,
    options: Options,
    imageLoader: ImageLoader,
): Decoder {
    return BitmapFactoryDecoder(
        source = result.source,
        options = options,
        parallelismLock = parallelismLock,
        exifOrientationStrategy = exifOrientationStrategy,
    )
}

override fun create(
    result: SourceFetchResult,
    options: Options,
    imageLoader: ImageLoader,
): Decoder? {
    if (!isApplicable(options)) return null
    val source = result.source.toImageDecoderSourceOrNull(options, animated = false) ?: return null
    return StaticImageDecoder(source, result.source, options, parallelismLock)
}

override fun isCacheValueValidForHardware(
    request: ImageRequest,
    cacheValue: MemoryCache.Value,
): Boolean {
    val image = cacheValue.image as? BitmapImage ?: return true
    val requestedConfig = image.bitmap.safeConfig
    return isConfigValidForHardware(request, requestedConfig)
}

@MainThread
    override fun onViewAttachedToWindow(v: View) {
        val request = currentRequest ?: return

        // As this is called from the main thread, isRestart will
        // be cleared synchronously as part of request.restart().
        isRestart = true
        request.restart()
    }

@Synchronized
    override fun shutdown() {
        if (shutdown) return
        shutdown = true

        application?.let { application ->
            activityCallbacks.unregister(application)
            application.unregisterComponentCallbacks(componentCallbacks)
        }
        imageLoader.clear()
    }

@JvmOverloads
    fun newDecoder(
        result: SourceFetchResult,
        options: Options,
        imageLoader: ImageLoader,
        startIndex: Int = 0,
    ): Pair<Decoder, Int>? {
        for (index in startIndex until decoderFactories.size) {
            val factory = decoderFactories[index]
            val decoder = factory.create(result, options, imageLoader)
            if (decoder != null) return decoder to index
        }
        return null
    }

