override fun remove(key: Key): Boolean = synchronized(lock) {
    // Do not short circuit. There is a regression test for this.
    val removedStrong = strongMemoryCache.remove(key)
    val removedWeak = weakMemoryCache.remove(key)
    return removedStrong || removedWeak
}

override fun enqueue(request: ImageRequest): Disposable {
    // Start executing the request on the main thread.
    val job = scope.async(options.mainCoroutineContextLazy.value) {
        execute(request, REQUEST_TYPE_ENQUEUE)
    }

    // Update the current request attached to the view and return a new disposable.
    return getDisposable(request, job)
}

fun getMimeTypeFromUrl(url: String): String? {
    if (url.isBlank()) {
        return null
    }

    val extension = url
        .substringBeforeLast('#') // Strip the fragment.
        .substringBeforeLast('?') // Strip the query.
        .substringAfterLast('/') // Get the last path segment.
        .substringAfterLast('.', missingDelimiterValue = "") // Get the file extension.

    return getMimeTypeFromExtension(extension)
}

internal fun ErrorResult(
    request: ImageRequest,
    throwable: Throwable,
): ErrorResult {
    return ErrorResult(
        image = if (throwable is NullRequestDataException) {
            request.fallback() ?: request.error()
        } else {
            request.error()
        },
        request = request,
        throwable = throwable,
    )
}

override fun create(
    result: SourceFetchResult,
    options: Options,
    imageLoader: ImageLoader,
): Decoder? {
    if (!isApplicable(result.source.source())) return null
    return AnimatedImageDecoder(result.source, options, enforceMinimumFrameDelay)
}

override fun create(
    result: SourceFetchResult,
    options: Options,
    imageLoader: ImageLoader,
): Decoder? {
    if (!DecodeUtils.isGif(result.source.source())) return null
    return GifDecoder(result.source, options, enforceMinimumFrameDelay)
}

internal fun BufferedSource.squashToDirectByteBuffer(): ByteBuffer {
    // Squash bytes to BufferedSource inner buffer then we know total byteCount.
    request(Long.MAX_VALUE)

    val byteBuffer = ByteBuffer.allocateDirect(buffer.size.toInt())
    while (!buffer.exhausted()) buffer.read(byteBuffer)
    byteBuffer.flip()
    return byteBuffer
}

override fun create(
    data: Uri,
    options: Options,
    imageLoader: ImageLoader,
): Fetcher? {
    if (!isApplicable(data)) return null
    return NetworkFetcher(
        url = data.toString(),
        options = options,
        networkClient = networkClientLazy,
        diskCache = lazy { imageLoader.diskCache },
        cacheStrategy = cacheStrategyLazy,
        connectivityChecker = lazyOf(connectivityCheckerLazy.get(options.context)),
        concurrentRequestStrategy = concurrentRequestStrategyLazy,
    )
}

private suspend fun HttpResponse.toNetworkResponse(): NetworkResponse {
    return NetworkResponse(
        code = status.value,
        requestMillis = requestTime.timestamp,
        responseMillis = responseTime.timestamp,
        headers = headers.toNetworkHeaders(),
        body = KtorNetworkResponseBody(bodyAsChannel()),
        delegate = this,
    )
}
